#include<bits/stdc++.h>
using namespace std;
#define ll long long
const int N=100005;
double a[N],b[N],ss[N],mn,mx;
int n,s,t;
bool check(double x)
{
	for(int i=1;i<=n;i++)
	{
		b[i]=a[i]-x;
		ss[i]=ss[i-1]+b[i];
	}
	deque<int> q;
	for(int i=s;i<=n;i++)
	{
		while(!q.empty()&&ss[q.front()]>ss[i-s]) q.pop_front();
		q.push_front(i-s);
		while(!q.empty()&&q.back()<i-t) q.pop_back();
		if(ss[i]>ss[q.back()]) return 1;
	}
	return 0;
}
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
	cin>>n>>s>>t;
	for(int i=1;i<=n;i++)
	{
		cin>>a[i];
		mn=min(mn,a[i]);
		mx=max(mx,a[i]);
	}
	double l=mn,r=mx,mid;
	while(l+0.0001<=r)
	{
		mid=(l+r)/2;
		if(check(mid)) l=mid;
		else r=mid;
	}
	cout<<fixed<<setprecision(3)<<l;
	return 0;
}
